SELECT AVG(attendance) AS above_average_attendance
FROM games
WHERE season = 'Season2023' AND attendance > (SELECT AVG(attendance) FROM games);

SELECT AVG(attendance) AS average_attendance
FROM games
WHERE stadium_id = 'NYK01' AND season = '2023';

SELECT event_description
FROM events
WHERE game_id = '1';

SELECT AVG(attendance) AS average_attendance
FROM games
WHERE season = '2022' AND weather_conditions = 'Sunny';

SELECT AVG(attendance) AS average_attendance
FROM games
WHERE season = '1928' AND attendance > 15000;

SELECT game_id, COUNT(*) AS substitution_count
FROM substitutions
GROUP BY game_id;
